export default {
	// Variáveis de controle e estado
	timeoutId: null,
	intervalId: null,
	tempoRestante: 3600, 
	tempoPadrao: 3600, 
	isCheckingCPF: false, // <-- Variável de trava que estava faltando

	// 1. Inicialização
	async aoCarregarPagina() {
		if (this.timeoutId) clearTimeout(this.timeoutId);
		if (this.intervalId) clearInterval(this.intervalId);
		this.tempoRestante = this.tempoPadrao;
		this.resetInactivityTimer();
	},

	// 2. Controle de Inatividade
	async resetInactivityTimer() {
		if (appsmith.store.currentTimeoutId) clearTimeout(appsmith.store.currentTimeoutId);
		if (appsmith.store.currentIntervalId) clearInterval(appsmith.store.currentIntervalId);

		this.tempoRestante = this.tempoPadrao;
		
		const newInterval = setInterval(() => {
			if (this.tempoRestante > 0) {
				this.tempoRestante--;
			}
		}, 1000);

		const newTimeout = setTimeout(async () => {
			await this.executarAutoLogoff();
		}, this.tempoPadrao * 1000);

		await storeValue("currentTimeoutId", newTimeout);
		await storeValue("currentIntervalId", newInterval);
	},
	
	formatarTempo() {
		const minutos = Math.floor(this.tempoRestante / 60);
		const segundos = this.tempoRestante % 60;
		return `${minutos}:${segundos < 10 ? '0' : ''}${segundos}`;
	},

	// 3. Funções de Saída e Limpeza
	async executarAutoLogoff() {
		await this.limparCamposEStore();
		showAlert("Sessão encerrada por inatividade.", "warning");
		navigateTo("home"); 
	},

	async limparESair() {
		await this.limparCamposEStore();
		showAlert("Sessão encerrada com segurança.", "info");
		navigateTo("home");
	},

	async limparCamposEStore() {
		await clearStore();
		const widgetsParaResetar = [
			"InputNome", "InputID", "InputRG", "InputCPF", "InputCEP", 
			"InputEndereco", "InputNumero", "InputComplemento", "InputBairro", 
			"InputCidade", "SelectUF", "InputEmail", "PhoneInput1Telefone", 
			"PhoneInput1Celular", "InputObservacao", "ImagePet", "FilePicker1Pet",
			"Input1Nome", "DatePicker1Nascimento", "Input2Idade", "Input3Peso",
			"Input3Registro", "Input3Microchip", "DatePicker1Obito",
			"Select1Especie", "Select1Raca", "Select1Sexo", "Select1Castrado",
			"Select1Porte", "Select1Pelagem", "Select1Cor", "Select1Temperamento",
			"Select1Convivio", "Select1Veterinario", "Select1Clinica",
			"Input1Canil", "Input1Pedigree", "Input1PedigreeNome",
			"Input1Observacao"
		];
		widgetsParaResetar.forEach(w => resetWidget(w, true));
	},

	// 4. Validação de CPF (Corrigida para disparar 1x)
	async validarCPFDuplicado() {
		if (this.isCheckingCPF) return;

		// Considera novo cadastro se o ID estiver vazio
		const ehNovoCadastro = !InputID.text || InputID.text === "";
		const cpfLimpo = (InputCPF.text || "").replace(/\D/g, "");

		if (ehNovoCadastro && cpfLimpo.length === 11) {
			try {
				this.isCheckingCPF = true; 

				await SelectCheckCPF.run();

				if (SelectCheckCPF.data && SelectCheckCPF.data.length > 0) {
					const registro = SelectCheckCPF.data[0];
					showAlert(`Atenção: Este CPF já está cadastrado para ${registro.prop001_nome}`, "warning");
					resetWidget("InputCPF");
				}
			} catch (error) {
				console.error("Erro na consulta de CPF", error);
			} finally {
				// Pequeno delay para liberar a trava e evitar duplicidade
				setTimeout(() => {
					this.isCheckingCPF = false;
				}, 800);
			}
		}
	},

	// 5. Utilidades
	currentSchema() {
		return appsmith.store.selectedSchema || "100000";
	},

// Função para definir a cor do texto baseado no status de permissão
	getPermitidoColor: (status) => {
		// Verifica se é booleano false ou a string "false"
		if (status === false || status === "false") {
			return "#fff1f1"; // Vermelho claro
		}
		return "#f0fdf4"; // Cor padrão do tema
	},

	customerLogo() {
		// Se você tiver o base64 no store, ele usa, senão retorna o texto fixo
		return appsmith.store.logoBase64 || ""; 
	}
}